import axios from 'axios';

const API_BASE = 'http://localhost:5000/api/testimonials';

export const getTestimonials = async () => {
  try {
    const res = await axios.get(API_BASE);
    // Map MongoDB data to frontend structure
    return res.data.map(item => ({
      id: item._id, // Map _id to id
      name: item.name,
      role: item.role,
      company: item.company,
      message: item.message,
      rating: item.rating,
      avatar: item.avatar || `/assets/testimonials/avatar${Math.floor(Math.random() * 3) + 1}.jpg` // Default avatar
    }));
  } catch (error) {
    console.error('Error fetching testimonials:', error);
    return [];
  }
};

export const addTestimonial = async (testimonial) => {
  try {
    const res = await axios.post(API_BASE, testimonial);
    return res.data;
  } catch (error) {
    console.error('Error adding testimonial:', error);
    throw new Error('Failed to add testimonial');
  }
};
